#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int min(int a, int b) {
    return (a < b) ? a : b;
}

int max(int a, int b) {
    return (a > b) ? a : b;
}

int calculateSimilarity(int a, int b) {
    return min((a * b) % MOD, (b * a) % MOD);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int *A = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        qsort(A, N, sizeof(int), compare);
        int maxSimilarity = 0;
        for (int i = 0; i < N - 1; i++) {
            int similarity = calculateSimilarity(A[i], A[i + 1]);
            maxSimilarity = max(maxSimilarity, similarity);
        }
        printf("%d\n", maxSimilarity);
        free(A);
    }
    return 0;
}

